import{_ as n,c as t,b as o,a as e,o as a}from"./app.7b8d607a.js";const v=JSON.parse('{"title":"Collatz Conjecture","description":"The simplest hardest problem in math history","frontmatter":{"title":"Collatz Conjecture","description":"The simplest hardest problem in math history"},"headers":[{"level":2,"title":"The Problem","slug":"the-problem"},{"level":2,"title":"The Person behind the Problem","slug":"the-person-behind-the-problem"},{"level":3,"title":"AC (Ante conjecture)","slug":"ac-ante-conjecture"},{"level":3,"title":"The conjecture","slug":"the-conjecture"},{"level":3,"title":"PC (Post conjecture)","slug":"pc-post-conjecture"},{"level":3,"title":"His books","slug":"his-books"},{"level":2,"title":"Solving the Problem","slug":"solving-the-problem"},{"level":3,"title":"The Plan","slug":"the-plan"},{"level":3,"title":"The Steps (Python)","slug":"the-steps-python"},{"level":3,"title":"The Reality","slug":"the-reality"},{"level":3,"title":"The \\"Solution\\"","slug":"the-solution"},{"level":2,"title":"Sources and Links","slug":"sources-and-links"}],"relativePath":"collatz-conjecture.md","lastUpdated":1658235123000}'),s={name:"collatz-conjecture.md"},r=e('<h1 id="collatz-conjecture" tabindex="-1">Collatz Conjecture <a class="header-anchor" href="#collatz-conjecture" aria-hidden="true">#</a></h1><p><strong>The simplest hardest problem in math history</strong></p><hr><div class="info custom-block"><p class="custom-block-title">Jeffery Lagarias, expert on the Collatz conjecture, mathematician at the University of Michigan</p><p>This is a really dangerous problem. People become obsessed with it and it really is impossible.</p></div><div class="info custom-block"><p class="custom-block-title">Paul Erd\xF6s, the man who only loved numbers</p><p>Mathematics is not ready for such problems yet.</p></div><div class="info custom-block"><p class="custom-block-title">Master of alliteration, me</p><p>Many, many mathematicians over the months of meaningless moil have made minimal progress toward the solution of this stupidly simple yet stubbornly unsolvable problem.</p></div><div class="info custom-block"><p class="custom-block-title">Pretty much every mathematician ever</p><p>Don&#39;t waste your time on this.</p></div><p>So, I wasted my time on this.</p><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-hidden="true">#</a></h2><p>So what&#39;s this Collatz conjecture thing? Well, if you haven&#39;t already watched <a href="https://www.youtube.com/watch?v=094y1Z2wpJg" target="_blank" rel="noopener noreferrer">Veritasium&#39;s video</a> about it, then here&#39;s the explanation.</p><ol><li><p>Take a positive whole number.</p></li><li><p>If it&#39;s even, halve it. If it&#39;s odd, multiply it by 3 and add 1.</p></li><li><p>Repeat step 2 until you reach 1.</p></li><li><p>Be confused about what the problem is here.</p></li><li><p>Read explanation below.</p></li></ol><p>The problem here is, we need to find a number that doesn&#39;t eventually reach 1 when you continue this sequence. Why? I have no clue, but it&#39;s an interesting puzzle nonetheless.</p><p>The conjecture suggests that there is no positive whole number that doesn&#39;t eventually reach 1. But that hasn&#39;t been proved (and probably won&#39;t be for a long time), hence why it&#39;s still a conjecture and not a theory.</p><h2 id="the-person-behind-the-problem" tabindex="-1">The Person behind the Problem <a class="header-anchor" href="#the-person-behind-the-problem" aria-hidden="true">#</a></h2><p><a href="https://en.wikipedia.org/wiki/Lothar_Collatz" target="_blank" rel="noopener noreferrer">Lothar Collatz</a> (1910-1990) was a German mathematician born in Arnsberg, Westphalia. He is most known for the Collatz conjecture, even though he did so much more.</p><h3 id="ac-ante-conjecture" tabindex="-1">AC (Ante conjecture) <a class="header-anchor" href="#ac-ante-conjecture" aria-hidden="true">#</a></h3><p>Collatz studied at a total of 4 universities before he got his doctorate. Yes, four.</p><ol><li><p>University of Greifswald</p></li><li><p>Ludwig Maximilian University of Munich</p></li><li><p>University of G\xF6ttingen</p></li><li><p>Humboldt University of Berlin</p><ul><li><p>This is where he studied for his doctorate under <a href="https://de.wikipedia.org/wiki/Alfred_Klose_(Mathematiker)" target="_blank" rel="noopener noreferrer">Alfred Klose</a>, a German mathematician who&#39;s Wikipedia page is only available in German.</p></li><li><p>Collatz was awarded his doctorate in 1935 for his dissertation <em>Das Differenzenverfahren mit h\xF6herer Approximation f\xFCr lineare Differentialgleichungen</em> (The finite difference method with higher approximation for linear differential equations).</p></li></ul></li></ol><p>After becoming a non-medical doctor, he worked as an assistant at the University of Berlin, and moved to the Technical University of Karlsruhe later that year.</p><h3 id="the-conjecture" tabindex="-1">The conjecture <a class="header-anchor" href="#the-conjecture" aria-hidden="true">#</a></h3><p>Collatz proposed his conjecture in 1937, just 2 years after being awarded his doctorate.</p><h3 id="pc-post-conjecture" tabindex="-1">PC (Post conjecture) <a class="header-anchor" href="#pc-post-conjecture" aria-hidden="true">#</a></h3><p>From 1938 to 1943 Collatz was a <a href="https://en.wikipedia.org/wiki/Privatdozent" target="_blank" rel="noopener noreferrer"><em>Privatdozent</em></a> at Karlsruhe. During the good old days of World War II, he worked with <a href="https://en.wikipedia.org/wiki/Alwin_Walther" target="_blank" rel="noopener noreferrer">Alwin Walther</a> at the Institute for Practical Mathematics of the Technische Hochschule Darmstadt.</p><p>In 1943, he was appointed to professorship at the Technical University of Hanover.</p><p>9 years later, in 1952, he moved to the University of Hamburg (the city where the name of hamburgers came from), where, in 1953, he founded the Institute of Applied Mathematics, which is the most original name ever. Collatz worked there until he stopped working, and retired.</p><p>Even after retirement, he was still very active on math conferences, and he died from a heart attack while attending one in Varna, Bulgaria in 1990.</p><h3 id="his-books" tabindex="-1">His books <a class="header-anchor" href="#his-books" aria-hidden="true">#</a></h3><p>This guy wrote a lot of books. The names are all in German and I&#39;m not gonna list them out here, but here&#39;s a list of a few if you want them. I&#39;m sure you can find more online.</p><p><a href="https://en.wikipedia.org/wiki/Lothar_Collatz#Selected_works" target="_blank" rel="noopener noreferrer">Lothar Collatz - Selected works (Wikipedia)</a></p><h2 id="solving-the-problem" tabindex="-1">Solving the Problem <a class="header-anchor" href="#solving-the-problem" aria-hidden="true">#</a></h2><h3 id="the-plan" tabindex="-1">The Plan <a class="header-anchor" href="#the-plan" aria-hidden="true">#</a></h3><p>Back to the topic, how are we gonna solve this problem? We can simplify this problem into 2 expressions:</p>',32),l={class:"MathJax",jax:"SVG",display:"true",style:{direction:"ltr",display:"block","text-align":"center",margin:"1em 0"}},i={style:{overflow:"visible","min-height":"1px","min-width":"1px","vertical-align":"-0.186ex"},xmlns:"http://www.w3.org/2000/svg",width:"6.322ex",height:"1.692ex",role:"img",focusable:"false",viewBox:"0 -666 2794.4 748"},p=e('<g stroke="currentColor" fill="currentColor" stroke-width="0" transform="scale(1,-1)"><g data-mml-node="math"><g data-mml-node="mn"><path data-c="33" d="M127 463Q100 463 85 480T69 524Q69 579 117 622T233 665Q268 665 277 664Q351 652 390 611T430 522Q430 470 396 421T302 350L299 348Q299 347 308 345T337 336T375 315Q457 262 457 175Q457 96 395 37T238 -22Q158 -22 100 21T42 130Q42 158 60 175T105 193Q133 193 151 175T169 130Q169 119 166 110T159 94T148 82T136 74T126 70T118 67L114 66Q165 21 238 21Q293 21 321 74Q338 107 338 175V195Q338 290 274 322Q259 328 213 329L171 330L168 332Q166 335 166 348Q166 366 174 366Q202 366 232 371Q266 376 294 413T322 525V533Q322 590 287 612Q265 626 240 626Q208 626 181 615T143 592T132 580H135Q138 579 143 578T153 573T165 566T175 555T183 540T186 520Q186 498 172 481T127 463Z" style="stroke-width:3;"></path></g><g data-mml-node="mi" transform="translate(500,0)"><path data-c="1D465" d="M52 289Q59 331 106 386T222 442Q257 442 286 424T329 379Q371 442 430 442Q467 442 494 420T522 361Q522 332 508 314T481 292T458 288Q439 288 427 299T415 328Q415 374 465 391Q454 404 425 404Q412 404 406 402Q368 386 350 336Q290 115 290 78Q290 50 306 38T341 26Q378 26 414 59T463 140Q466 150 469 151T485 153H489Q504 153 504 145Q504 144 502 134Q486 77 440 33T333 -11Q263 -11 227 52Q186 -10 133 -10H127Q78 -10 57 16T35 71Q35 103 54 123T99 143Q142 143 142 101Q142 81 130 66T107 46T94 41L91 40Q91 39 97 36T113 29T132 26Q168 26 194 71Q203 87 217 139T245 247T261 313Q266 340 266 352Q266 380 251 392T217 404Q177 404 142 372T93 290Q91 281 88 280T72 278H58Q52 284 52 289Z" style="stroke-width:3;"></path></g><g data-mml-node="mo" transform="translate(1294.2,0)"><path data-c="2B" d="M56 237T56 250T70 270H369V420L370 570Q380 583 389 583Q402 583 409 568V270H707Q722 262 722 250T707 230H409V-68Q401 -82 391 -82H389H387Q375 -82 369 -68V230H70Q56 237 56 250Z" style="stroke-width:3;"></path></g><g data-mml-node="mn" transform="translate(2294.4,0)"><path data-c="31" d="M213 578L200 573Q186 568 160 563T102 556H83V602H102Q149 604 189 617T245 641T273 663Q275 666 285 666Q294 666 302 660V361L303 61Q310 54 315 52T339 48T401 46H427V0H416Q395 3 257 3Q121 3 100 0H88V46H114Q136 46 152 46T177 47T193 50T201 52T207 57T213 61V578Z" style="stroke-width:3;"></path></g></g></g>',1),h=[p],c={class:"MathJax",jax:"SVG",display:"true",style:{direction:"ltr",display:"block","text-align":"center",margin:"1em 0"}},d={style:{overflow:"visible","min-height":"1px","min-width":"1px","vertical-align":"-1.552ex"},xmlns:"http://www.w3.org/2000/svg",width:"2.29ex",height:"4.081ex",role:"img",focusable:"false",viewBox:"0 -1118 1012 1804"},u=e('<g stroke="currentColor" fill="currentColor" stroke-width="0" transform="scale(1,-1)"><g data-mml-node="math"><g data-mml-node="mfrac"><g data-mml-node="mi" transform="translate(220,676)"><path data-c="1D465" d="M52 289Q59 331 106 386T222 442Q257 442 286 424T329 379Q371 442 430 442Q467 442 494 420T522 361Q522 332 508 314T481 292T458 288Q439 288 427 299T415 328Q415 374 465 391Q454 404 425 404Q412 404 406 402Q368 386 350 336Q290 115 290 78Q290 50 306 38T341 26Q378 26 414 59T463 140Q466 150 469 151T485 153H489Q504 153 504 145Q504 144 502 134Q486 77 440 33T333 -11Q263 -11 227 52Q186 -10 133 -10H127Q78 -10 57 16T35 71Q35 103 54 123T99 143Q142 143 142 101Q142 81 130 66T107 46T94 41L91 40Q91 39 97 36T113 29T132 26Q168 26 194 71Q203 87 217 139T245 247T261 313Q266 340 266 352Q266 380 251 392T217 404Q177 404 142 372T93 290Q91 281 88 280T72 278H58Q52 284 52 289Z" style="stroke-width:3;"></path></g><g data-mml-node="mn" transform="translate(256,-686)"><path data-c="32" d="M109 429Q82 429 66 447T50 491Q50 562 103 614T235 666Q326 666 387 610T449 465Q449 422 429 383T381 315T301 241Q265 210 201 149L142 93L218 92Q375 92 385 97Q392 99 409 186V189H449V186Q448 183 436 95T421 3V0H50V19V31Q50 38 56 46T86 81Q115 113 136 137Q145 147 170 174T204 211T233 244T261 278T284 308T305 340T320 369T333 401T340 431T343 464Q343 527 309 573T212 619Q179 619 154 602T119 569T109 550Q109 549 114 549Q132 549 151 535T170 489Q170 464 154 447T109 429Z" style="stroke-width:3;"></path></g><rect width="772" height="60" x="120" y="220"></rect></g></g></g>',1),m=[u],y=e(`<p>Now that we have those, we can turn it into a program to make the computer do all the work for us. I&#39;m gonna be using Python for this, because it&#39;s one of the easier programming languages to understand and I&#39;m more comfortable with it. If you have a different preference, feel free to use your own preferred language to write the program.</p><h3 id="the-steps-python" tabindex="-1">The Steps (Python) <a class="header-anchor" href="#the-steps-python" aria-hidden="true">#</a></h3><p>Follow these few easy steps and you&#39;ll be on your way to solving this problem in no time:</p><ol><li><p>Download and install <a href="https://www.python.org/" target="_blank" rel="noopener noreferrer">Python (programming language)</a></p></li><li><p>Download and install a code editor. I used <a href="https://atom.io/" target="_blank" rel="noopener noreferrer">Atom</a> and later IDLE (included with Python, would not recommend using) for this, but you can use any code editor you like. If you use an online one, you may not have to install Python at all.</p></li><li><p>Make a new Python program and type in the following code:</p></li></ol><div class="language-py"><span class="copy"></span><pre><code><span class="line"><span style="color:#C792EA;">def</span><span style="color:#EEFFFF;"> </span><span style="color:#82AAFF;">collatz</span><span style="color:#89DDFF;">(</span><span style="color:#EEFFFF;">n</span><span style="color:#89DDFF;">):</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># make collatz function</span></span>
<span class="line"><span style="color:#EEFFFF;">    </span><span style="color:#89DDFF;font-style:italic;">while</span><span style="color:#EEFFFF;"> n </span><span style="color:#89DDFF;">!=</span><span style="color:#EEFFFF;"> </span><span style="color:#F78C6C;">1</span><span style="color:#89DDFF;">:</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># tell code to keep running until it reaches 1</span></span>
<span class="line"><span style="color:#EEFFFF;">        </span><span style="color:#89DDFF;font-style:italic;">if</span><span style="color:#EEFFFF;"> n </span><span style="color:#89DDFF;">%</span><span style="color:#EEFFFF;"> </span><span style="color:#F78C6C;">2</span><span style="color:#89DDFF;">:</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># if number is odd, multiply by 3 and add 1</span></span>
<span class="line"><span style="color:#EEFFFF;">            n </span><span style="color:#89DDFF;">=</span><span style="color:#EEFFFF;"> n</span><span style="color:#89DDFF;">*</span><span style="color:#F78C6C;">3</span><span style="color:#EEFFFF;"> </span><span style="color:#89DDFF;">+</span><span style="color:#EEFFFF;"> </span><span style="color:#F78C6C;">1</span></span>
<span class="line"><span style="color:#EEFFFF;">        </span><span style="color:#89DDFF;font-style:italic;">else</span><span style="color:#89DDFF;">:</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># else, if number is even, halve it</span></span>
<span class="line"><span style="color:#EEFFFF;">            n </span><span style="color:#89DDFF;">=</span><span style="color:#EEFFFF;"> n </span><span style="color:#89DDFF;">/</span><span style="color:#EEFFFF;"> </span><span style="color:#F78C6C;">2</span></span>
<span class="line"><span style="color:#EEFFFF;">        </span><span style="color:#82AAFF;">print</span><span style="color:#89DDFF;">(</span><span style="color:#82AAFF;">n</span><span style="color:#89DDFF;">)</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># output number onto screen</span></span>
<span class="line"></span>
<span class="line"><span style="color:#EEFFFF;">num </span><span style="color:#89DDFF;">=</span><span style="color:#EEFFFF;"> </span><span style="color:#FFCB6B;">int</span><span style="color:#89DDFF;">(</span><span style="color:#82AAFF;">input</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Enter a number to test: </span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">))</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># ask user for number to test</span></span>
<span class="line"><span style="color:#82AAFF;">collatz</span><span style="color:#89DDFF;">(</span><span style="color:#82AAFF;">num</span><span style="color:#89DDFF;">)</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># run the collatz function with the number you type in</span></span>
<span class="line"><span style="color:#82AAFF;">input</span><span style="color:#89DDFF;">()</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># Press enter to exit</span></span>
<span class="line"></span></code></pre></div><p>Alternatively, you can <a href="collatz-conjecture/collatz-conjecture.py" title="Right click and save as to download">download the code here</a>.</p><ol start="4"><li><p>Hit save and double-click the .py file to run it.</p></li><li><p>Enter a number when it tells you to &quot;Enter a number to test: &quot;</p></li><li><p>Wait until the output reaches 1.</p></li><li><p>Realise you&#39;ve wasted possibly hours of your day setting everything up, and writing and rewriting the code, trying to make everything work properly, only to realise that the program only goes up to 2<sup>1024</sup> because there&#39;s something wrong with the code, since Python 3 isn&#39;t supposed to have an integer limit and even though everything had <code>int()</code> around it, it was still working in floats for whatever reason, until you finally remove all the <code>int()</code>s and succumb to the limit that the system has forced upon you.</p></li><li><p>Question the choices you made that brought you to this point in your life.</p></li></ol><p>Seems simple enough, wouldn&#39;t you say?</p><h3 id="the-reality" tabindex="-1">The Reality <a class="header-anchor" href="#the-reality" aria-hidden="true">#</a></h3><p>As you can probably tell, that didn&#39;t end up going too well. No matter what number you put in there, it all seems to go to 1 sooner or later. Don&#39;t worry, that&#39;s a problem that mathematicians of the world have been dealing with for the last 84 years (as of 2021).</p><p>As for my code, I&#39;m sure there&#39;s a much better way to do this than what I&#39;ve written. You can find those online, but I made this program myself, and I&#39;m (kinda) happy with it. There&#39;s probably also a way to automate this so that it tests all the numbers for you, but I liked the idea of being able to try your own numbers to see if they work or not.</p><p>But, if the idea of taking a year off to try every single number up to 2<sup>1024</sup> manually in this program sounds appealing to you, then you really need something exciting in your life, buddy. But other than that, go ahead, give this problem a try. Maybe if you try for long enough, you might find yourself an answer.</p><h3 id="the-solution" tabindex="-1">The &quot;Solution&quot; <a class="header-anchor" href="#the-solution" aria-hidden="true">#</a></h3><p>So far, there&#39;s been no solutions. That&#39;s not really a conclusion since it can&#39;t be proven that there&#39;s no solution. Just like how it can&#39;t be proven that there <em>is</em> a solution.</p><p><a href="https://en.wikipedia.org/wiki/Terence_Tao" target="_blank" rel="noopener noreferrer">Terence Tao</a>, kid genius who&#39;s no longer a kid but still a genius, gave this problem a go. He found a &quot;solution&quot;, which is that <em>almost</em> all numbers reach 1, which gives us a pretty good estimate of the actual solution. You can read about it in his <a href="https://terrytao.wordpress.com/2011/08/25/the-collatz-conjecture-littlewood-offord-theory-and-powers-of-2-and-3/" target="_blank" rel="noopener noreferrer">blog post</a>. I didn&#39;t understand any of it, but maybe you will.</p><div class="info custom-block"><p class="custom-block-title">Terence Tao, genius, mathematician</p><p>It\u2019s actually an occupational hazard when you\u2019re a mathematician. You could get obsessed with these big famous problems that are way beyond anyone\u2019s ability to touch, and you can waste a lot of time.</p></div><p>I found a thesis by Jose William Porras that claims to be the &quot;Solution to Collatz&#39;s Conjecture&quot;. You can have a read <a href="https://www.researchgate.net/publication/325389892_Solution_to_Collatz&#39;s_Conjecture" target="_blank" rel="noopener noreferrer">here</a>. Again, I didn&#39;t understand it, but maybe you will.</p><h2 id="sources-and-links" tabindex="-1">Sources and Links <a class="header-anchor" href="#sources-and-links" aria-hidden="true">#</a></h2><p><a href="https://www.wikidata.org/wiki/Property:P69" target="_blank" rel="noopener noreferrer">List of universities attended by Lothar Collatz</a></p><p><a href="https://www.quantamagazine.org/mathematician-proves-huge-result-on-dangerous-problem-20191211/" target="_blank" rel="noopener noreferrer">Simpler explanation of Terence Tao&#39;s &quot;solution&quot;</a></p><p><a href="https://en.wikipedia.org/wiki/Collatz_conjecture" target="_blank" rel="noopener noreferrer">Collatz conjecture Wikipedia page</a></p><p><a href="https://mathshistory.st-andrews.ac.uk/Biographies/Collatz/" target="_blank" rel="noopener noreferrer">Lother Collatz biography</a></p><p><a href="https://www.youtube.com/playlist?list=PLPa2dwCo_Eqker6ktrUs7dC7FkKwa7Q2h" target="_blank" rel="noopener noreferrer">YouTube playlist about Collatz conjecture (includes Veritasium video)</a></p><p><strong>All other sources are linked in the main text</strong></p><hr><h4 id="contributors" tabindex="-1">Contributors <a class="header-anchor" href="#contributors" aria-hidden="true">#</a></h4><p class="contributors"><a href="https://github.com/noClaps" target="_blank" rel="noopener noreferrer"><img src="https://github.com/noClaps.png?size=32" alt="" title="noClaps" class="contrib"></a></p>`,27);function f(g,b,F,w,T,Q){return a(),t("div",null,[r,o("mjx-container",l,[(a(),t("svg",i,h))]),o("mjx-container",c,[(a(),t("svg",d,m))]),y])}var k=n(s,[["render",f]]);export{v as __pageData,k as default};
